SELECT COUNT(DISTINCT v.case_id) AS total_cases
FROM vaccinations v
INNER JOIN hospitalizations h ON v.case_id = h.case_id;

SELECT DISTINCT v.vaccine_type
FROM vaccinations v
JOIN hospitalizations h ON v.case_id = h.case_id;

SELECT vaccine_type
FROM vaccinations
WHERE vaccination_id = 0;

SELECT DISTINCT vaccine_type
FROM vaccinations
WHERE vaccination_date >= '2021-01-01';

SELECT MIN(vaccination_date) AS earliest_vaccination_date
FROM vaccinations
WHERE vaccine_type IN ('Pfizer', 'Moderna');

SELECT MIN(v.vaccination_date) AS earliest_vaccination_date
FROM vaccinations v
INNER JOIN hospitalizations h ON v.case_id = h.case_id;

SELECT COUNT(DISTINCT v.case_id) AS total_cases
FROM vaccinations v
JOIN hospitalizations h ON v.case_id = h.case_id;
